    % Simple Calculator in MATLAB
    clear;
    clc;
    fprintf('Welcome to the Simple Calculator!\n');

    while true
        fprintf('Enter the operation you want to perform (+, -, *, /) or "exit" to quit: ');
        operation = input('');

        if strcmp(operation, 'exit')
            fprintf('Exiting the calculator. Goodbye!\n');
            break;
        end

        if ~ischar(operation) || ~isnumeric(input('Enter the first number: ')) || ~isnumeric(input('Enter the second number: '))
            fprintf('Invalid input. Please enter valid numbers.\n');
            continue;
        end

        num1 = input('Enter the first number: ');
        num2 = input('Enter the second number: ');

        switch operation
            case '+'
                result = num1 + num2;
            case '-'
                result = num1 - num2;
            case '*'
                result = num1 * num2;
            case '/'
                if num2 == 0
                    fprintf('Error: Division by zero is not allowed.\n');
                else
                    result = num1 / num2;
                end
            otherwise
                fprintf('Invalid operation. Please use +, -, *, or /.\n');
                continue;
        end

        fprintf('The result is: %f\n', result);
    end
end
```

### How to Run the Code:
1. Save the code in a `.m` file, for example, `simpleCalculator.m`.
2. Open MATLAB and run the script by typing `simpleCalculator()` in the Command Window.
