#include <iostream>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    int pipefd[2]; // Array to hold the file descriptors for the pipe

    // Create a pipe
    if (pipe(pipefd) == -1) {
        std::cerr << "Pipe creation failed" << std::endl;
        return 1;
    }

    pid_t pid = fork();

    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) { // Child process
        // Close the write end of the pipe (no longer needed)
        close(pipefd[1]);

        // Redirect stdin and stdout to the pipe
        dup2(pipefd[0], STDIN_FILENO);
        dup2(pipefd[0], STDOUT_FILENO);

        // Execute a command, for example, a shell
        execlp("/bin/sh", "sh", "-c", "echo 'Hello from child process'", nullptr);

        // If execlp fails, print an error and exit
        std::cerr << "Command execution failed" << std::endl;
        _exit(1);
    } else { // Parent process
        // Close the read end of the pipe (no longer needed)
        close(pipefd[0]);

        // Write something to the child process
        write(pipefd[1], "Hello from parent process\n", 28);

        // Wait for the child process to finish
        waitpid(pid, nullptr, 0);

        // Close the write end of the pipe
        close(pipefd[1]);

